public class FilePathSeparator {

    /** 
     * अंतिम निर्देशिका विभाजक वर्ण का अनुक्रमांक लौटाता है। <p> यह विधि फ़ाइल को यूनिक्स या विंडोज़ प्रारूप में संभालेगी। अंतिम फॉरवर्ड या बैकस्लैश की स्थिति लौटाई जाती है। <p> आउटपुट उस मशीन के अनुसार समान होगा जिस पर कोड चल रहा है।
     * @param filename  वह फ़ाइल नाम जिसमें अंतिम पथ विभाजक को खोजना है, null होने पर -1 लौटाता है
     * @return अंतिम विभाजक वर्ण का अनुक्रमांक, या -1 यदि ऐसा कोई वर्ण नहीं है
     */
    public static int indexOfLastSeparator(String filename) {
        if (filename == null) {
            return -1;
        }

        int lastForwardSlash = filename.lastIndexOf('/');
        int lastBackSlash = filename.lastIndexOf('\\');

        return Math.max(lastForwardSlash, lastBackSlash);
    }

    public static void main(String[] args) {
        // Test cases
        System.out.println(indexOfLastSeparator("C:\\Users\\User\\Documents\\file.txt")); // Output: 20
        System.out.println(indexOfLastSeparator("/home/user/documents/file.txt")); // Output: 15
        System.out.println(indexOfLastSeparator("file.txt")); // Output: -1
        System.out.println(indexOfLastSeparator(null)); // Output: -1
    }
}

private int parseEndOfLine(String headerPart, int end) {
    // Check if the end index is within the bounds of the headerPart string
    if (end < 0 || end >= headerPart.length()) {
        throw new IllegalArgumentException("End index is out of bounds");
    }

    // Find the end of the line by searching for the line terminators
    int lineEnd = headerPart.indexOf("\r\n", end);
    if (lineEnd == -1) {
        lineEnd = headerPart.indexOf('\n', end);
    }
    if (lineEnd == -1) {
        // If no line end is found, return the length of the headerPart
        return headerPart.length();
    }

    // Return the index of the end of the line
    return lineEnd + 2; // +2 to include the length of the line terminators
}

public class StringSearch {
    /** 
     * एक स्ट्रिंग के भीतर अंतिम अनुक्रमांक खोजता है, <code>null</code> को संभालते हुए। यह विधि {@link String#lastIndexOf(String)} का उपयोग करती है। 
     */
    public static int lastIndexOf(String str, String searchStr) {
        if (str == null || searchStr == null) {
            return -1;
        }
        return str.lastIndexOf(searchStr);
    }

    public static void main(String[] args) {
        // उदाहरण के लिए परीक्षण
        String str = "Hello, world! Hello, universe!";
        String searchStr = "Hello";
        int index = lastIndexOf(str, searchStr);
        System.out.println("The last index of '" + searchStr + "' is: " + index);
    }
}

