public class DigitChecker {
    /** 
     * <p>जांचता है कि <code>String</code> में केवल अंक के अक्षर हैं या नहीं।</p> 
     * <p><code>Null</code> और खाली String <code>false</code> लौटाएगा।</p>
     * @param str  जांचने के लिए <code>String</code>
     * @return <code>true</code> यदि str में केवल यूनिकोड संख्या है
     */
    public static boolean isDigits(String str) {
        if (str == null || str.isEmpty()) {
            return false;
        }
        for (char c : str.toCharArray()) {
            if (!Character.isDigit(c)) {
                return false;
            }
        }
        return true;
    }

    public static void main(String[] args) {
        System.out.println(isDigits("12345")); // true
        System.out.println(isDigits("123a5")); // false
        System.out.println(isDigits(""));      // false
        System.out.println(isDigits(null));    // false
    }
}

public class ParameterSeparatorChecker {

    /** 
     * यह निर्धारित करें कि क्या एक पैरामीटर नाम वर्तमान स्थिति पर समाप्त होता है, अर्थात्, क्या दिया गया वर्ण एक विभाजक के रूप में योग्य है। 
     */
    private static boolean isParameterSeparator(final char c) {
        // Define the valid parameter separators
        return c == ',' || c == ';' || c == '&' || c == '|';
    }

    public static void main(String[] args) {
        // Test the isParameterSeparator method
        char testChar1 = ',';
        char testChar2 = 'a';

        System.out.println(isParameterSeparator(testChar1)); // true
        System.out.println(isParameterSeparator(testChar2)); // false
    }
}

public class StringUtils {

    /** 
     * <p>जांचें कि एक String एक निर्दिष्ट उपसर्ग के साथ समाप्त होता है (वैकल्पिक रूप से केस संवेदनशीलता को अनदेखा करते हुए)।</p>
     * @see String#endsWith(String)
     * @param str  वह String जिसे जांचना है, यह null हो सकता है
     * @param suffix वह उपसर्ग जिसे खोजना है, यह null हो सकता है
     * @param ignoreCase यह दर्शाता है कि तुलना में केस को अनदेखा करना चाहिए या नहीं (केस संवेदनशीलता को अनदेखा करना)।
     * @return <code>true</code> यदि String उपसर्ग के साथ शुरू होता है या दोनों <code>null</code> हैं
     */
    private static boolean endsWith(final String str, final String suffix, final boolean ignoreCase) {
        if (str == null && suffix == null) {
            return true;
        }
        if (str == null || suffix == null) {
            return false;
        }
        if (ignoreCase) {
            return str.toLowerCase().endsWith(suffix.toLowerCase());
        } else {
            return str.endsWith(suffix);
        }
    }

    public static void main(String[] args) {
        System.out.println(endsWith("HelloWorld", "World", false)); // true
        System.out.println(endsWith("HelloWorld", "world", true));  // true
        System.out.println(endsWith(null, null, false));            // true
        System.out.println(endsWith("HelloWorld", null, false));    // false
        System.out.println(endsWith(null, "World", false));         // false
    }
}

import java.net.URI;
import java.util.ArrayList;
import java.util.List;

public class PathSegmentDecoder {

    /** 
     * URI के पथ घटक को पथ खंडों के रूप में डिकोड करें।
     * @param u URI। यदि पथ घटक एक पूर्ण पथ घटक है, तो अग्रणी '/' को अनदेखा किया जाता है और इसे पथ खंड के विभाजक के रूप में नहीं माना जाता है।
     * @param decode यदि पथ घटक के पथ खंडों को डिकोडेड रूप में होना चाहिए तो true।
     * @return पथ खंडों की सूची।
     */
    public static List<PathSegmentImpl> decodePath(URI u, boolean decode) {
        List<PathSegmentImpl> segments = new ArrayList<>();
        String path = u.getPath();

        // Remove leading '/' if present
        if (path.startsWith("/")) {
            path = path.substring(1);
        }

        // Split the path into segments
        String[] parts = path.split("/");

        for (String part : parts) {
            if (decode) {
                part = decodeURIComponent(part);
            }
            segments.add(new PathSegmentImpl(part));
        }

        return segments;
    }

    private static String decodeURIComponent(String component) {
        try {
            return java.net.URLDecoder.decode(component, "UTF-8");
        } catch (Exception e) {
            return component; // Return the original if decoding fails
        }
    }

    // Dummy implementation of PathSegmentImpl for demonstration purposes
    public static class PathSegmentImpl {
        private String segment;

        public PathSegmentImpl(String segment) {
            this.segment = segment;
        }

        @Override
        public String toString() {
            return segment;
        }
    }
}

public class ArrayUtil {

    private static final Character[] EMPTY_ARRAY = new Character[0];

    /** 
     * <p>एक रक्षात्मक प्रोग्रामिंग तकनीक जो <code>null</code> संदर्भ को एक खाली संदर्भ में बदलती है।</p> 
     * <p>यह विधि <code>null</code> इनपुट ऐरे के लिए एक खाली ऐरे लौटाती है।</p> 
     * <p>एक मेमोरी ऑप्टिमाइजिंग तकनीक के रूप में, एक खाली ऐरे जो पास किया गया है, इसे इस वर्ग में खाली <code>public static</code> संदर्भों के साथ ओवरराइड किया जाएगा।</p>
     * @param array  वह ऐरे जिसे <code>null</code> या खाली के लिए जांचना है
     * @return वही ऐरे, <code>public static</code> खाली ऐरे यदि <code>null</code> या खाली इनपुट हो
     * @since 2.5
     */
    public static Character[] nullToEmpty(final Character[] array) {
        if (array == null || array.length == 0) {
            return EMPTY_ARRAY;
        }
        return array;
    }

    public static void main(String[] args) {
        Character[] nullArray = null;
        Character[] emptyArray = {};
        Character[] filledArray = {'A', 'B', 'C'};

        System.out.println(nullToEmpty(nullArray).length); // Output: 0
        System.out.println(nullToEmpty(emptyArray).length); // Output: 0
        System.out.println(nullToEmpty(filledArray).length); // Output: 3
    }
}

public class Example {

    private Throwable thrown;

    public Example(Throwable thrown) {
        this.thrown = thrown;
    }

    /** 
     * @return यदि getThrown().toString() एक गैर-खाली स्ट्रिंग है तो true लौटाता है।
     */
    public boolean hasThrown() {
        return thrown != null && !thrown.toString().isEmpty();
    }

    public Throwable getThrown() {
        return thrown;
    }

    public static void main(String[] args) {
        Example example = new Example(new Exception("An error occurred"));
        System.out.println(example.hasThrown()); // Output: true

        Example example2 = new Example(null);
        System.out.println(example2.hasThrown()); // Output: false
    }
}

import java.util.Stack;

public class DiagnosisStack {
    private static Stack<String> diagnosisStack = new Stack<>();

    /** 
     * इस NDC के शीर्ष पर अंतिम निदान संदर्भ को देखता है बिना उसे हटाए। <p> लौटाई गई मान वह मान है जो अंतिम बार डाला गया था। यदि कोई संदर्भ उपलब्ध नहीं है, तो खाली स्ट्रिंग "" लौटाई जाती है।
     * @return String सबसे आंतरिक निदान संदर्भ।
     */
    public static String peek() {
        if (diagnosisStack.isEmpty()) {
            return "";
        }
        return diagnosisStack.peek();
    }

    // Method to push a diagnosis reference onto the stack
    public static void push(String diagnosis) {
        diagnosisStack.push(diagnosis);
    }

    // Method to pop a diagnosis reference from the stack
    public static String pop() {
        if (!diagnosisStack.isEmpty()) {
            return diagnosisStack.pop();
        }
        return "";
    }

    public static void main(String[] args) {
        push("Diagnosis 1");
        push("Diagnosis 2");
        System.out.println(peek()); // Output: Diagnosis 2
        pop();
        System.out.println(peek()); // Output: Diagnosis 1
        pop();
        System.out.println(peek()); // Output: (empty string)
    }
}

import java.util.HashMap;
import java.util.Map;

public class ValueAccumulator {
    private Map<String, Long> map;

    public ValueAccumulator() {
        map = new HashMap<>();
    }

    /** 
     * दिए गए कुंजी में मौजूदा मान के साथ मान को जोड़ें।
     */
    public void valueAccumulation(String key, Long value) {
        map.put(key, map.getOrDefault(key, 0L) + value);
    }

    public Long getValue(String key) {
        return map.getOrDefault(key, 0L);
    }

    public static void main(String[] args) {
        ValueAccumulator accumulator = new ValueAccumulator();
        accumulator.valueAccumulation("a", 10L);
        accumulator.valueAccumulation("a", 5L);
        System.out.println(accumulator.getValue("a")); // Output: 15
    }
}

import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;
import java.io.InputStream;

public class FileIterator {
    private File[] files;
    private int currentIndex;

    public FileIterator(File[] files) {
        this.files = files;
        this.currentIndex = 0;
    }

    /** 
     * अगला {@link java.io.File} ऑब्जेक्ट लौटाएं या {@code null} लौटाएं यदि कोई और फ़ाइल उपलब्ध नहीं है।
     */
    public InputStream next() throws IOException {
        if (currentIndex < files.length) {
            File file = files[currentIndex++];
            return new FileInputStream(file);
        }
        return null;
    }
}

import java.util.logging.Logger;

public class LoggerChecker {

    /**
     * जांचें कि क्या नामित लॉगर पदानुक्रम में मौजूद है। यदि हाँ, तो इसका संदर्भ लौटाएँ, अन्यथा <code>null</code> लौटाएँ।
     * @param name उस लॉगर का नाम जिसे खोजा जाना है।
     */
    public Logger exists(String name) {
        Logger logger = Logger.getLogger(name);
        return logger.getHandlers().length > 0 ? logger : null;
    }

    public static void main(String[] args) {
        LoggerChecker checker = new LoggerChecker();
        Logger logger = checker.exists("myLogger");
        if (logger != null) {
            System.out.println("Logger exists: " + logger.getName());
        } else {
            System.out.println("Logger does not exist.");
        }
    }
}

