import java.util.Stack;

public class FrameStack {
    private Stack<Object> stack;

    public FrameStack() {
        this.stack = new Stack<>();
    }

    /**
     * आउटपुट फ्रेम स्टैक से जितने भी अमूर्त प्रकार हैं, उन्हें दिए गए वर्णनकर्ता के अनुसार पॉप करता है।
     * @param descriptor एक प्रकार या विधि का वर्णनकर्ता (जिसमें इसके तर्क प्रकार पॉप होते हैं)।
     */
    private void pop(final String descriptor) {
        // Assuming descriptor is a string representation of types
        String[] types = descriptor.split(",");
        for (String type : types) {
            if (!stack.isEmpty()) {
                Object poppedValue = stack.pop();
                // Here you can add logic to check the type of poppedValue
                // and ensure it matches the expected type from descriptor
                System.out.println("Popped: " + poppedValue + " of type: " + type);
            } else {
                System.out.println("Stack is empty, cannot pop more values.");
                break;
            }
        }
    }

    public void push(Object value) {
        stack.push(value);
    }

    public static void main(String[] args) {
        FrameStack frameStack = new FrameStack();
        frameStack.push(1);
        frameStack.push("Hello");
        frameStack.push(3.14);

        frameStack.pop("Integer,String,Double");
    }
}

import java.io.IOException;
import java.io.OutputStream;

public class CustomOutputStream extends OutputStream {
    @Override
    public void write(final byte b[], final int off, final int len) throws IOException {
        if (b == null) {
            throw new NullPointerException("Byte array is null");
        }
        if (off < 0 || len < 0 || off + len > b.length) {
            throw new IndexOutOfBoundsException("Invalid offset or length");
        }

        // Here you would implement the logic to write the bytes to the output stream.
        // For demonstration, we will just print the bytes being written.
        for (int i = off; i < off + len; i++) {
            System.out.print((char) b[i]); // Print as characters for demonstration
        }
    }

    @Override
    public void write(int b) throws IOException {
        // Implement the method to write a single byte if needed
        System.out.print((char) b); // Print as character for demonstration
    }

    public static void main(String[] args) throws IOException {
        CustomOutputStream customOutputStream = new CustomOutputStream();
        byte[] data = "Hello, World!".getBytes();
        customOutputStream.write(data, 0, data.length);
    }
}

public class ArrayUtils {
    /** 
     * दिए गए ऐरे में निर्दिष्ट अनुक्रमांक पर दो तत्वों का आदान-प्रदान करता है।
     * @param < V > ऐरे में तत्वों का प्रकार
     * @param arr ऐरे
     * @param i पहले तत्व का अनुक्रमांक
     * @param j दूसरे तत्व का अनुक्रमांक
     */
    public static final <V> void swap(V[] arr, int i, int j) {
        if (arr == null || i < 0 || j < 0 || i >= arr.length || j >= arr.length) {
            throw new IllegalArgumentException("Invalid index or null array");
        }
        V temp = arr[i];
        arr[i] = arr[j];
        arr[j] = temp;
    }

    public static void main(String[] args) {
        Integer[] array = {1, 2, 3, 4, 5};
        System.out.println("Before swap: " + java.util.Arrays.toString(array));
        swap(array, 1, 3);
        System.out.println("After swap: " + java.util.Arrays.toString(array));
    }
}

