}

import java.util.HashMap;
import java.util.HashSet;
import java.util.Map;
import java.util.Set;

public class Graph<V, E> {
    private Map<V, Set<Edge<E>>> adjacencyList;

    public Graph() {
        adjacencyList = new HashMap<>();
    }

    protected void addToIndex(V sourceVertex, V targetVertex, E e) {
        adjacencyList.putIfAbsent(sourceVertex, new HashSet<>());
        adjacencyList.putIfAbsent(targetVertex, new HashSet<>());

        adjacencyList.get(sourceVertex).add(new Edge<>(targetVertex, e));
    }

    private static class Edge<E> {
        V targetVertex;
        E edge;

        Edge(V targetVertex, E edge) {
            this.targetVertex = targetVertex;
            this.edge = edge;
        }
    }
}

import java.io.File;

public class ClassPathExample {

    /** 
     * वर्तमान JVM उदाहरण का क्लास पथ {@link File} ऑब्जेक्ट्स के एक ऐरे के रूप में लौटाता है।
     */
    private static File[] classPath() {
        String classPath = System.getProperty("java.class.path");
        String[] paths = classPath.split(System.getProperty("path.separator"));
        File[] files = new File[paths.length];

        for (int i = 0; i < paths.length; i++) {
            files[i] = new File(paths[i]);
        }

        return files;
    }

    public static void main(String[] args) {
        File[] classPathFiles = classPath();
        for (File file : classPathFiles) {
            System.out.println(file.getAbsolutePath());
        }
    }
}

public class StringArrayCopy {

    /** 
     * यह विधि प्रदान किए गए ऐरे की एक प्रति बनाती है, और सुनिश्चित करती है कि नए बनाए गए ऐरे में सभी स्ट्रिंग केवल छोटे अक्षरों में हों। 
     * <p> इस विधि का उपयोग स्ट्रिंग ऐरे की नकल करने के लिए करने का मतलब है कि src ऐरे में किए गए परिवर्तन dst ऐरे को संशोधित नहीं करते हैं।
     */
    private static String[] copyStrings(final String[] src) {
        if (src == null) {
            return null;
        }

        String[] dst = new String[src.length];
        for (int i = 0; i < src.length; i++) {
            dst[i] = src[i] != null ? src[i].toLowerCase() : null;
        }
        return dst;
    }

    public static void main(String[] args) {
        String[] original = {"Hello", "World", "JAVA", null, "Programming"};
        String[] copied = copyStrings(original);

        // Print the copied array
        for (String str : copied) {
            System.out.println(str);
        }
    }
}

