import com.alibaba.fastjson.JSON;
import com.alibaba.fastjson.JSONWriter;

public class JsonSerializer {

    /** 
     * JSON में सीरियलाइज़ करें {@link String}
     * @param features सीरियलाइज़ेशन में सक्षम करने के लिए विशेषताएँ
     * @return JSON {@link String}
     */
    @SuppressWarnings("unchecked")
    public String toString(JSONWriter.Feature... features) {
        // Example object to serialize
        MyObject obj = new MyObject("example", 123);

        // Serialize the object to JSON string with the provided features
        return JSON.toJSONString(obj, features);
    }

    // Example class to demonstrate serialization
    public static class MyObject {
        private String name;
        private int value;

        public MyObject(String name, int value) {
            this.name = name;
            this.value = value;
        }

        // Getters and setters (if needed)
        public String getName() {
            return name;
        }

        public void setName(String name) {
            this.name = name;
        }

        public int getValue() {
            return value;
        }

        public void setValue(int value) {
            this.value = value;
        }
    }

    public static void main(String[] args) {
        JsonSerializer serializer = new JsonSerializer();
        String jsonString = serializer.toString(JSONWriter.Feature.PrettyFormat);
        System.out.println(jsonString);
    }
}

import java.lang.reflect.Method;

public class Converter {

    /**
     * <p>इनपुट ऑब्जेक्ट को java.lang.Character में परिवर्तित करें।</p>
     * @param type वह डेटा प्रकार जिसमें इस मान को परिवर्तित किया जाना चाहिए।
     * @param value वह इनपुट मान जिसे परिवर्तित किया जाना है।
     * @return परिवर्तित मान।
     * @throws Exception यदि परिवर्तित करना सफलतापूर्वक नहीं किया जा सकता है
     * @since 1.8.0
     */
    @Override
    protected Object convertToType(final Class<?> type, final Object value) throws Exception {
        if (value == null) {
            return null;
        }
        if (type == Character.class) {
            if (value instanceof String) {
                String strValue = (String) value;
                if (strValue.length() == 1) {
                    return strValue.charAt(0);
                } else {
                    throw new Exception("String must be of length 1 to convert to Character.");
                }
            } else if (value instanceof Character) {
                return value;
            } else {
                throw new Exception("Unsupported type for conversion to Character.");
            }
        }
        throw new Exception("Unsupported target type: " + type.getName());
    }
}

import java.util.List;

public class StringUtils {
    /** 
     * केस-संवेदनशीलता की परवाह किए बिना जांच करता है कि स्ट्रिंग में दिए गए स्ट्रिंग सेट में कोई भी वर्ण है या नहीं। 
     */
    public static boolean containsAnyIgnoreCase(String str, List<String> searchStrArray) {
        if (str == null || searchStrArray == null) {
            return false;
        }
        String lowerStr = str.toLowerCase();
        for (String searchStr : searchStrArray) {
            if (searchStr != null && lowerStr.contains(searchStr.toLowerCase())) {
                return true;
            }
        }
        return false;
    }

    public static void main(String[] args) {
        // Example usage
        List<String> searchStrings = List.of("hello", "world", "java");
        String testString = "Hello there!";
        boolean result = containsAnyIgnoreCase(testString, searchStrings);
        System.out.println(result); // Output: true
    }
}

public class PrimeCapacity {

    /**
     * एक प्रमुख संख्या लौटाता है जो <code>&gt;= desiredCapacity</code> है और <code>desiredCapacity</code> के बहुत करीब है (यदि <code>desiredCapacity &gt;= 1000</code> है तो 11% के भीतर)।
     * @param desiredCapacity उपयोगकर्ता द्वारा इच्छित क्षमता।
     * @return वह क्षमता जो हैशटेबल के लिए उपयोग की जानी चाहिए।
     */
    public static int nextPrime(int desiredCapacity) {
        if (desiredCapacity <= 1) {
            return 2;
        }
        int capacity = desiredCapacity;
        if (capacity % 2 == 0) {
            capacity++;
        }
        while (true) {
            if (isPrime(capacity)) {
                if (desiredCapacity >= 1000) {
                    int upperLimit = (int) (desiredCapacity * 1.11);
                    if (capacity <= upperLimit) {
                        return capacity;
                    }
                } else {
                    return capacity;
                }
            }
            capacity += 2; // Check only odd numbers
        }
    }

    private static boolean isPrime(int number) {
        if (number <= 1) {
            return false;
        }
        if (number <= 3) {
            return true;
        }
        if (number % 2 == 0 || number % 3 == 0) {
            return false;
        }
        for (int i = 5; i * i <= number; i += 6) {
            if (number % i == 0 || number % (i + 2) == 0) {
                return false;
            }
        }
        return true;
    }

    public static void main(String[] args) {
        int desiredCapacity = 1000;
        int primeCapacity = nextPrime(desiredCapacity);
        System.out.println("Next prime capacity: " + primeCapacity);
    }
}

public class CharUtils {
    /** 
     * <p>Character को char में परिवर्तित करता है और <code>null</code> को संभालता है।</p> 
     * <pre> 
     * CharUtils.toChar(null, 'X') = 'X' 
     * CharUtils.toChar(' ', 'X')  = ' ' 
     * CharUtils.toChar('A', 'X')  = 'A' 
     * </pre>
     * @param ch  वह चर जिसे परिवर्तित करना है
     * @param defaultValue  वह मान जिसका उपयोग किया जाएगा यदि Character null है
     * @return Character का char मान या null होने पर डिफ़ॉल्ट मान
     */
    public static char toChar(final Character ch, final char defaultValue) {
        return (ch != null) ? ch : defaultValue;
    }

    public static void main(String[] args) {
        System.out.println(toChar(null, 'X')); // Output: X
        System.out.println(toChar(' ', 'X'));  // Output:  
        System.out.println(toChar('A', 'X'));  // Output: A
    }
}

import java.util.Collection;

public class MatchFinder {
    /** 
     * '<code>candidates</code>' में से पहला तत्व लौटाएं जो '<code>source</code>' में मौजूद है। यदि '<code>candidates</code>' में कोई तत्व '<code>source</code>' में नहीं है, तो <code>null</code> लौटाएं। पुनरावृत्ति का क्रम {@link Collection} कार्यान्वयन विशिष्ट है।
     * @param source स्रोत संग्रह
     * @param candidates खोजने के लिए उम्मीदवार
     * @return पहला मौजूद वस्तु, या यदि नहीं मिला तो <code>null</code>
     */
    public static Object findFirstMatch(Collection source, Collection candidates) {
        for (Object candidate : candidates) {
            if (source.contains(candidate)) {
                return candidate;
            }
        }
        return null;
    }
}

public class StringUtil {

    /** 
     * दिए गए String से अंतिमWhitespace को हटाएं।
     * @param str वह String जिसे जांचना है
     * @return ट्रिम किया हुआ String
     * @see java.lang.Character#isWhitespace
     */
    public static String trimTrailingWhitespace(String str) {
        if (str == null) {
            return null;
        }

        int end = str.length();
        while (end > 0 && Character.isWhitespace(str.charAt(end - 1))) {
            end--;
        }

        return str.substring(0, end);
    }

    public static void main(String[] args) {
        String testString = "Hello World!   ";
        String trimmedString = trimTrailingWhitespace(testString);
        System.out.println("Original: '" + testString + "'");
        System.out.println("Trimmed: '" + trimmedString + "'");
    }
}

