import java.util.Objects;

public class ArrayConverter {
    /** 
     * <p>एक ऑब्जेक्ट इंटीजर के एरे को प्राइमिटिव में परिवर्तित करता है।</p> 
     * <p>यह विधि <code>null</code> इनपुट एरे के लिए <code>null</code> लौटाती है।</p>
     * @param array  एक <code>Integer</code> एरे, जो <code>null</code> हो सकता है
     * @return एक <code>int</code> एरे, यदि इनपुट एरे <code>null</code> है तो <code>null</code>
     * @throws NullPointerException यदि एरे की सामग्री <code>null</code> है
     */
    public static int[] toPrimitive(final Integer[] array) {
        if (array == null) {
            return null;
        }
        int[] result = new int[array.length];
        for (int i = 0; i < array.length; i++) {
            if (array[i] == null) {
                throw new NullPointerException("Array contains null element at index " + i);
            }
            result[i] = array[i];
        }
        return result;
    }
}

import java.lang.reflect.Method;

public class ObjectRegistrar {

    /** 
     * <p> दिए गए ऑब्जेक्ट को रजिस्टर करता है। अनंत लूप से बचने के लिए रिफ्लेक्शन विधियों द्वारा उपयोग किया जाता है। </p>
     * @param value रजिस्टर करने के लिए ऑब्जेक्ट।
     */
    static void register(Object value) {
        if (value == null) {
            throw new IllegalArgumentException("Cannot register a null object.");
        }

        Class<?> clazz = value.getClass();
        Method[] methods = clazz.getDeclaredMethods();

        System.out.println("Registering object of class: " + clazz.getName());
        for (Method method : methods) {
            System.out.println("Found method: " + method.getName());
        }

        // Additional registration logic can be added here
    }

    public static void main(String[] args) {
        // Example usage
        Object myObject = new String("Hello, World!");
        register(myObject);
    }
}

public class NonZeroCounter {

    /**
     * एक पंक्ति के गैर-शून्य प्रविष्टियों की संख्या प्राप्त करें।
     * @param row पंक्ति
     * @return एक पंक्ति के गैर-शून्य प्रविष्टियों की संख्या
     */
    public int nonZeros(int[] row) {
        int count = 0;
        for (int num : row) {
            if (num != 0) {
                count++;
            }
        }
        return count;
    }

    public static void main(String[] args) {
        NonZeroCounter counter = new NonZeroCounter();
        int[] row = {1, 0, 2, 0, 3, 4, 0};
        System.out.println("गैर-शून्य प्रविष्टियों की संख्या: " + counter.nonZeros(row));
    }
}

import java.util.Collection;

public class CollectionUtils {
    /** 
     * जांचें कि दी गई संग्रह में दी गई तत्व उदाहरण मौजूद है या नहीं। <p>सुनिश्चित करता है कि दी गई उदाहरण मौजूद है, न कि समान तत्व के लिए <code>true</code> लौटाने के लिए।
     * @param collection जांचने के लिए संग्रह
     * @param element खोजने के लिए तत्व
     * @return <code>true</code> यदि पाया गया, <code>false</code> अन्यथा
     */
    public static boolean containsInstance(Collection<?> collection, Object element) {
        for (Object obj : collection) {
            if (obj == element) {
                return true;
            }
        }
        return false;
    }
}

public class CharUtils {
    /** 
     * <p>जांच करता है कि क्या वर्ण ASCII 7 बिट नियंत्रण है।</p> 
     * <pre> 
     * CharUtils.isAsciiControl('a')  = false 
     * CharUtils.isAsciiControl('A')  = false 
     * CharUtils.isAsciiControl('3')  = false 
     * CharUtils.isAsciiControl('-')  = false 
     * CharUtils.isAsciiControl('\n') = true 
     * CharUtils.isAsciiControl('&copy;') = false 
     * </pre>
     * @param ch  जांचने के लिए वर्ण
     * @return यदि 32 से कम या 127 के बराबर है तो true
     */
    public static boolean isAsciiControl(final char ch) {
        return ch < 32 || ch == 127;
    }

    public static void main(String[] args) {
        System.out.println(isAsciiControl('a'));  // false
        System.out.println(isAsciiControl('A'));  // false
        System.out.println(isAsciiControl('3'));  // false
        System.out.println(isAsciiControl('-'));  // false
        System.out.println(isAsciiControl('\n')); // true
        System.out.println(isAsciiControl('\u00A9')); // false
    }
}

