import java.util.HashMap;
import java.util.Map;

public class ConstantPool {
    private final Map<String, Integer> constantNameAndTypeMap;
    private int nextIndex;

    public ConstantPool() {
        this.constantNameAndTypeMap = new HashMap<>();
        this.nextIndex = 1; // Start indexing from 1
    }

    /**
     * इस प्रतीक तालिका के स्थायी पूल में एक CONSTANT_NameAndType_info जोड़ता है। यदि स्थायी पूल में पहले से ही समान आइटम मौजूद है, तो कुछ नहीं करता है।
     * @param name एक फ़ील्ड या विधि का नाम।
     * @param descriptor एक फ़ील्ड या विधि का विवरण।
     * @return दिए गए मान के साथ एक नया या पहले से मौजूद प्रतीक।
     */
    public int addConstantNameAndType(final String name, final String descriptor) {
        String key = name + ":" + descriptor;
        if (!constantNameAndTypeMap.containsKey(key)) {
            constantNameAndTypeMap.put(key, nextIndex++);
        }
        return constantNameAndTypeMap.get(key);
    }

    public static void main(String[] args) {
        ConstantPool pool = new ConstantPool();
        int index1 = pool.addConstantNameAndType("myField", "I");
        int index2 = pool.addConstantNameAndType("myField", "I");
        int index3 = pool.addConstantNameAndType("myMethod", "(I)V");

        System.out.println("Index of myField: " + index1); // Should print 1
        System.out.println("Index of myField again: " + index2); // Should print 1
        System.out.println("Index of myMethod: " + index3); // Should print 2
    }
}

public class StringUnescaper {

    /** 
     * एक स्ट्रिंग DOT पहचानकर्ता को अनएस्केप करें।
     * @param input इनपुट
     * @return अनएस्केप किया गया आउटपुट
     */
    private String unescapeId(String input) {
        if (input == null) {
            return null;
        }

        StringBuilder output = new StringBuilder();
        boolean isEscaped = false;

        for (char c : input.toCharArray()) {
            if (isEscaped) {
                output.append(c);
                isEscaped = false;
            } else if (c == '\\') {
                isEscaped = true;
            } else {
                output.append(c);
            }
        }

        return output.toString();
    }

    public static void main(String[] args) {
        StringUnescaper unescaper = new StringUnescaper();
        String input = "Hello\\ World\\!";
        String output = unescaper.unescapeId(input);
        System.out.println(output); // Output: Hello World!
    }
}

import java.util.ArrayList;
import java.util.List;

public class ArrayConcatenation {

    /** 
     * दिए गए String arrays को एक में जोड़ें, जिसमें ओवरलैपिंग array तत्वों को दो बार शामिल किया गया है। <p> मूल arrays में तत्वों का क्रम संरक्षित रहता है।
     * @param array1 पहला array (यह <code>null</code> हो सकता है)
     * @param array2 दूसरा array (यह <code>null</code> हो सकता है)
     * @return नया array (<code>null</code> यदि दोनों दिए गए arrays <code>null</code> थे)
     */
    public static String[] concatenateStringArrays(String[] array1, String[] array2) {
        if (array1 == null && array2 == null) {
            return null;
        }

        List<String> resultList = new ArrayList<>();

        if (array1 != null) {
            for (String s : array1) {
                resultList.add(s);
            }
        }

        if (array2 != null) {
            for (String s : array2) {
                resultList.add(s);
            }
        }

        return resultList.toArray(new String[0]);
    }

    public static void main(String[] args) {
        String[] array1 = {"apple", "banana", "cherry"};
        String[] array2 = {"banana", "date", "fig"};

        String[] result = concatenateStringArrays(array1, array2);
        for (String s : result) {
            System.out.println(s);
        }
    }
}

import java.util.List;
import java.util.Set;

public class BucketRelabeler {

    /**
     * {@code minLabel} लेबल वाले बकेट से सभी वर्टिस को लेबल 0 वाले बकेट में स्थानांतरित करता है। {@code minLabel} लेबल वाले बकेट को साफ करता है। लेबलिंग को तदनुसार अपडेट करता है।
     * @param bucketsByLabel वे बकेट जहाँ वर्टिस संग्रहीत हैं
     * @param labels वर्टिस के लेबल
     * @param minLabel गैर-खाली बकेट का न्यूनतम मान
     */
    private void reload(List<Set<Integer>> bucketsByLabel, List<Integer> labels, int minLabel) {
        if (minLabel < 0 || minLabel >= bucketsByLabel.size()) {
            throw new IllegalArgumentException("minLabel is out of bounds");
        }

        Set<Integer> minLabelBucket = bucketsByLabel.get(minLabel);
        Set<Integer> zeroLabelBucket = bucketsByLabel.get(0);

        // Move vertices from minLabel bucket to zero label bucket
        for (Integer vertex : minLabelBucket) {
            zeroLabelBucket.add(vertex);
            labels.set(vertex, 0); // Update the label of the vertex to 0
        }

        // Clear the minLabel bucket
        minLabelBucket.clear();
    }
}

import java.util.Arrays;

public class StringArrayUtil {

    /** 
     * दिए गए स्ट्रिंग को दिए गए स्ट्रिंग एरे में जोड़ें, एक नया एरे लौटाते हुए जिसमें इनपुट एरे की सामग्री और दिया गया स्ट्रिंग शामिल हो।
     * @param array वह एरे जिसमें जोड़ना है (यह <code>null</code> हो सकता है)
     * @param str वह स्ट्रिंग जिसे जोड़ना है
     * @return नया एरे (कभी भी <code>null</code> नहीं)
     */
    public static String[] addStringToArray(String[] array, String str) {
        if (array == null) {
            return new String[]{str};
        }

        String[] newArray = Arrays.copyOf(array, array.length + 1);
        newArray[array.length] = str;
        return newArray;
    }

    public static void main(String[] args) {
        String[] originalArray = {"Hello", "World"};
        String newString = "!";
        String[] updatedArray = addStringToArray(originalArray, newString);

        System.out.println(Arrays.toString(updatedArray)); // Output: [Hello, World, !]
    }
}

public class SubstringCounter {

    /** 
     * स्ट्रिंग {@code str} में उपस्ट्रिंग {@code sub} की उपस्थिति की संख्या लौटाता है।
     * @param str वह स्ट्रिंग जिसमें खोज करनी है। यदि यह null है तो 0 लौटाएं।
     * @param sub वह स्ट्रिंग जिसे खोजा जाना है। यदि यह null है तो 0 लौटाएं।
     * @return स्ट्रिंग {@code str} में उपस्ट्रिंग {@code sub} की उपस्थिति की संख्या।
     */
    public static int countOccurrencesOf(String str, String sub) {
        if (str == null || sub == null) {
            return 0;
        }

        int count = 0;
        int index = 0;

        while ((index = str.indexOf(sub, index)) != -1) {
            count++;
            index += sub.length();
        }

        return count;
    }

    public static void main(String[] args) {
        String str = "hello world, hello universe";
        String sub = "hello";
        int occurrences = countOccurrencesOf(str, sub);
        System.out.println("Occurrences of '" + sub + "': " + occurrences);
    }
}

