public class FilePathUtil {

    /** 
     * दिए गए पथ से फ़ाइल नाम का एक्सटेंशन हटा दें, जैसे "mypath/myfile.txt" -&gt; "mypath/myfile"।
     * @param path फ़ाइल का पथ (यह <code>null</code> हो सकता है)
     * @return फ़ाइल नाम के एक्सटेंशन के बिना पथ, या <code>null</code> यदि कोई नहीं है
     */
    public static String stripFilenameExtension(String path) {
        if (path == null) {
            return null;
        }

        int lastDotIndex = path.lastIndexOf('.');
        int lastSlashIndex = Math.max(path.lastIndexOf('/'), path.lastIndexOf('\\'));

        if (lastDotIndex > lastSlashIndex) {
            return path.substring(0, lastDotIndex);
        }

        return path;
    }

    public static void main(String[] args) {
        String path = "mypath/myfile.txt";
        System.out.println(stripFilenameExtension(path)); // Output: mypath/myfile
    }
}

public class CharacterArrayConverter {

    /** 
     * <p>एक ऑब्जेक्ट कैरेक्टर्स के एरे को प्रिमिटिव्स में परिवर्तित करता है।</p> 
     * <p>यह विधि <code>null</code> इनपुट एरे के लिए <code>null</code> लौटाती है।</p>
     * @param array  एक <code>Character</code> एरे, यह <code>null</code> हो सकता है
     * @return एक <code>char</code> एरे, यदि इनपुट एरे <code>null</code> है तो <code>null</code>
     * @throws NullPointerException यदि एरे की सामग्री <code>null</code> है
     */
    public static char[] toPrimitive(final Character[] array) {
        if (array == null) {
            return null;
        }
        char[] result = new char[array.length];
        for (int i = 0; i < array.length; i++) {
            if (array[i] == null) {
                throw new NullPointerException("Array element at index " + i + " is null");
            }
            result[i] = array[i];
        }
        return result;
    }

    public static void main(String[] args) {
        // Example usage
        Character[] charArray = { 'a', 'b', 'c' };
        char[] primitiveArray = toPrimitive(charArray);
        for (char c : primitiveArray) {
            System.out.print(c + " ");
        }
    }
}

public class TokenParser {

    /**
     * एक टोकन को पार्स करता है जब तक कि दिए गए किसी भी समाप्ति चिन्ह का सामना नहीं किया जाता।
     * @param terminators समाप्ति वर्णों का ऐरे। इनमें से कोई भी वर्ण जब सामना किया जाता है, तो यह टोकन के अंत का संकेत देता है
     * @return टोकन
     */
    private String parseToken(final char[] terminators) {
        StringBuilder token = new StringBuilder();
        int ch;

        try {
            while ((ch = System.in.read()) != -1) {
                char currentChar = (char) ch;
                if (isTerminator(currentChar, terminators)) {
                    break;
                }
                token.append(currentChar);
            }
        } catch (IOException e) {
            e.printStackTrace();
        }

        return token.toString();
    }

    private boolean isTerminator(char currentChar, char[] terminators) {
        for (char terminator : terminators) {
            if (currentChar == terminator) {
                return true;
            }
        }
        return false;
    }

    public static void main(String[] args) {
        TokenParser parser = new TokenParser();
        char[] terminators = {' ', '\n', '\t', ',', '.'}; // Example terminators
        String token = parser.parseToken(terminators);
        System.out.println("Parsed Token: " + token);
    }
}

public class Main {
    /**
     * दिए गए स्ट्रिंग से प्रदान किए गए अग्रणी वर्ण के सभी उदाहरणों को हटाएं।
     * @param str वह स्ट्रिंग जिसे जांचना है
     * @param leadingCharacter वह अग्रणी वर्ण जिसे हटाना है
     * @return हटाई गई स्ट्रिंग
     */
    public static String trimLeadingCharacter(String str, char leadingCharacter) {
        if (str == null || str.isEmpty()) {
            return str;
        }

        int startIndex = 0;
        while (startIndex < str.length() && str.charAt(startIndex) == leadingCharacter) {
            startIndex++;
        }

        return str.substring(startIndex);
    }

    public static void main(String[] args) {
        String result = trimLeadingCharacter("aaabbbccc", 'a');
        System.out.println(result); // Output: bbbccc
    }
}

public class ArrayConverter {

    /** 
     * <p>प्राथमिक int के एक ऐरे को ऑब्जेक्ट्स में परिवर्तित करता है।</p> 
     * <p>यह विधि <code>null</code> इनपुट ऐरे के लिए <code>null</code> लौटाती है।</p>
     * @param array  एक <code>int</code> ऐरे
     * @return एक <code>Integer</code> ऐरे, <code>null</code> यदि null ऐरे इनपुट है
     */
    public static Integer[] toObject(final int[] array) {
        if (array == null) {
            return null;
        }

        Integer[] result = new Integer[array.length];
        for (int i = 0; i < array.length; i++) {
            result[i] = array[i]; // Autoboxing from int to Integer
        }
        return result;
    }

    public static void main(String[] args) {
        int[] primitiveArray = {1, 2, 3, 4, 5};
        Integer[] objectArray = toObject(primitiveArray);

        // Print the result
        for (Integer num : objectArray) {
            System.out.print(num + " ");
        }
    }
}

