import java.util.ArrayList;
import java.util.List;
import javafx.util.Pair;

public class SuffixSumCalculator {

    /** 
     * {@code bounds} का एक सुफिक्स सम की गणना करता है। गणना की गई सुफिक्स सम और {@code bounds list} में सभी तत्वों का योग लौटाता है।
     * @param bounds पूर्णांकों की सूची।
     * @return गणना की गई सुफिक्स सम सूची और सभी तत्वों का योग।
     */
    private Pair<List<Integer>, Long> computeSuffixSum(List<Integer> bounds) {
        List<Integer> suffixSum = new ArrayList<>();
        long totalSum = 0;
        int n = bounds.size();

        // Calculate the suffix sum
        for (int i = n - 1; i >= 0; i--) {
            totalSum += bounds.get(i);
            suffixSum.add(0, totalSum); // Add to the front to maintain order
        }

        return new Pair<>(suffixSum, totalSum);
    }
}

public class ArrayReverser {
    /** 
     * निर्दिष्ट सीमा के भीतर दिए गए ऐरे में तत्वों के क्रम को उलटता है।
     * @param < V > ऐरे में तत्वों का प्रकार
     * @param arr ऐरे
     * @param from उलटने के लिए सीमा के भीतर पहले तत्व का अनुक्रमांक (समावेशी)
     * @param to उलटने के लिए सीमा के भीतर अंतिम तत्व का अनुक्रमांक (समावेशी)
     */
    public static final <V> void reverse(V[] arr, int from, int to) {
        if (arr == null || from < 0 || to >= arr.length || from >= to) {
            throw new IllegalArgumentException("Invalid indices or array is null");
        }

        while (from < to) {
            V temp = arr[from];
            arr[from] = arr[to];
            arr[to] = temp;
            from++;
            to--;
        }
    }

    public static void main(String[] args) {
        Integer[] array = {1, 2, 3, 4, 5};
        reverse(array, 1, 3);
        for (Integer num : array) {
            System.out.print(num + " ");
        }
    }
}

import java.util.LinkedList;

class ListNode<E> {
    E data;
    ListNode<E> next;
    ListNode<E> prev;

    ListNode(E data) {
        this.data = data;
    }
}

class DoublyLinkedList<E> {
    private ListNode<E> head;
    private ListNode<E> tail;

    public void addListNode(ListNode<E> node) {
        if (head == null) {
            head = node;
            tail = node;
        } else {
            tail.next = node;
            node.prev = tail;
            tail = node;
        }
    }

    public void removeListNode(ListNode<E> node) {
        if (node.prev != null) {
            node.prev.next = node.next;
        } else {
            head = node.next;
        }
        if (node.next != null) {
            node.next.prev = node.prev;
        } else {
            tail = node.prev;
        }
    }

    public ListNode<E> getHead() {
        return head;
    }
}

public class ListNodeMover<E> {
    private void moveAllListNodes(DoublyLinkedList<E> list) {
        ListNode<E> current = list.getHead();
        while (current != null) {
            ListNode<E> nextNode = current.next; // Store next node
            list.removeListNode(current); // Remove from original list
            list.addListNode(current); // Add to the new list
            current = nextNode; // Move to the next node
        }
    }
}

public class StringUtils {

    /** 
     * <p>जांचें कि एक String एक निर्दिष्ट उपसर्ग से शुरू होता है (वैकल्पिक रूप से केस-इंसेंसिटिव)।</p>
     * @see String#startsWith(String)
     * @param str  वह String जिसे जांचना है, यह null हो सकता है
     * @param prefix वह उपसर्ग जिसे खोजना है, यह null हो सकता है
     * @param ignoreCase यह दर्शाता है कि तुलना में केस को नजरअंदाज करना चाहिए या नहीं (केस-इंसेंसिटिव)।
     * @return <code>true</code> यदि String उपसर्ग से शुरू होता है या दोनों <code>null</code> हैं
     */
    private static boolean startsWith(final String str, final String prefix, final boolean ignoreCase) {
        if (str == null && prefix == null) {
            return true;
        }
        if (str == null || prefix == null) {
            return false;
        }
        if (ignoreCase) {
            return str.toLowerCase().startsWith(prefix.toLowerCase());
        } else {
            return str.startsWith(prefix);
        }
    }

    public static void main(String[] args) {
        System.out.println(startsWith("HelloWorld", "Hello", false)); // true
        System.out.println(startsWith("HelloWorld", "hello", true));  // true
        System.out.println(startsWith("HelloWorld", "World", false)); // false
        System.out.println(startsWith(null, null, false));             // true
        System.out.println(startsWith(null, "Hello", false));         // false
    }
}

public class CharUtils {
    private static final Character[] cache = new Character[128];

    static {
        for (int i = 0; i < cache.length; i++) {
            cache[i] = (char) i;
        }
    }

    /**
     * <p>चरित्र को एक Character में परिवर्तित करता है।</p> 
     * <p>ASCII 7 बिट चरित्रों के लिए, यह एक कैश का उपयोग करता है जो हर बार वही Character ऑब्जेक्ट लौटाता है।</p> 
     * <pre> CharUtils.toCharacterObject(' ')  = ' ' CharUtils.toCharacterObject('A')  = 'A' </pre>
     * @param ch  वह चरित्र जिसे परिवर्तित करना है
     * @return निर्दिष्ट चरित्र का एक Character
     */
    public static Character toCharacterObject(final char ch) {
        if (ch >= 0 && ch < 128) {
            return cache[ch];
        }
        return new Character(ch);
    }

    public static void main(String[] args) {
        System.out.println(CharUtils.toCharacterObject(' ')); // Output: ' '
        System.out.println(CharUtils.toCharacterObject('A')); // Output: 'A'
        System.out.println(CharUtils.toCharacterObject('Z')); // Output: 'Z'
        System.out.println(CharUtils.toCharacterObject((char) 128)); // Output: ''
    }
}

public class CharUtils {
    /** 
     * <p>जांचता है कि क्या वर्ण ASCII 7 बिट वर्णमाला के बड़े अक्षर हैं।</p> 
     * <pre> 
     * CharUtils.isAsciiAlphaUpper('a')  = false 
     * CharUtils.isAsciiAlphaUpper('A')  = true 
     * CharUtils.isAsciiAlphaUpper('3')  = false 
     * CharUtils.isAsciiAlphaUpper('-')  = false 
     * CharUtils.isAsciiAlphaUpper('\n') = false 
     * CharUtils.isAsciiAlphaUpper('&copy;') = false 
     * </pre>
     * @param ch  जांचने के लिए वर्ण
     * @return 65 और 90 के बीच (समावेशी) होने पर true
     */
    public static boolean isAsciiAlphaUpper(final char ch) {
        return ch >= 65 && ch <= 90;
    }

    public static void main(String[] args) {
        System.out.println(isAsciiAlphaUpper('a')); // false
        System.out.println(isAsciiAlphaUpper('A')); // true
        System.out.println(isAsciiAlphaUpper('3')); // false
        System.out.println(isAsciiAlphaUpper('-')); // false
        System.out.println(isAsciiAlphaUpper('\n')); // false
        System.out.println(isAsciiAlphaUpper('©')); // false
    }
}

import org.apache.log4j.spi.LoggingEvent;

public class FilterExample {

    public static final int NEUTRAL = 0;

    /**
     * यदि कोई स्ट्रिंग मेल नहीं खाता है तो {@link Filter#NEUTRAL} लौटाता है।
     */
    public int decide(LoggingEvent event) {
        // यहाँ पर लॉजिक जोड़े जो यह निर्धारित करता है कि क्या स्ट्रिंग मेल खाता है
        String message = event.getMessage().toString();

        // उदाहरण के लिए, हम एक निश्चित स्ट्रिंग की तुलना करेंगे
        String targetString = "target";

        if (!message.contains(targetString)) {
            return NEUTRAL;
        }

        // अन्य निर्णयों के लिए कोड यहाँ जोड़ें
        return 1; // उदाहरण के लिए, मेल खाने पर 1 लौटाएँ
    }

    public static void main(String[] args) {
        // परीक्षण के लिए एक उदाहरण लॉगिंग इवेंट बनाएँ
        LoggingEvent event = new LoggingEvent("logger", null, System.currentTimeMillis(), 0, "This is a test message", null);
        FilterExample filterExample = new FilterExample();
        int result = filterExample.decide(event);
        System.out.println("Decision: " + result);
    }
}

import java.util.HashSet;
import java.util.Set;

public class Template {
    private Set<String> templateVariables;

    public Template() {
        templateVariables = new HashSet<>();
    }

    public void addTemplateVariable(String name) {
        templateVariables.add(name);
    }

    /** 
     * यह सुनिश्चित करें कि एक टेम्पलेट वेरिएबल इस टेम्पलेट का सदस्य है या नहीं।
     * @param name नाम टेम्पलेट वेरिएबल।
     * @return यदि टेम्पलेट वेरिएबल टेम्पलेट का सदस्य है, तो true, अन्यथा false।
     */
    public final boolean isTemplateVariablePresent(String name) {
        return templateVariables.contains(name);
    }

    public static void main(String[] args) {
        Template template = new Template();
        template.addTemplateVariable("variable1");
        System.out.println(template.isTemplateVariablePresent("variable1")); // true
        System.out.println(template.isTemplateVariablePresent("variable2")); // false
    }
}

import org.apache.commons.beanutils.BeanMap;
import java.beans.PropertyDescriptor;
import java.lang.reflect.Method;

public class BeanMapUtil {

    /**
     * दिए गए BeanMap से सभी लिखने योग्य गुणों को इस BeanMap में डालता है। केवल पढ़ने योग्य और केवल लिखने योग्य गुणों को नजरअंदाज किया जाएगा।
     * @param map  वह BeanMap जिसके गुणों को डालना है
     */
    public void putAllWriteable(BeanMap map) {
        if (map == null) {
            throw new IllegalArgumentException("BeanMap cannot be null");
        }

        Object bean = map.getBean();
        PropertyDescriptor[] propertyDescriptors = java.beans.Introspector.getBeanInfo(bean.getClass()).getPropertyDescriptors();

        for (PropertyDescriptor descriptor : propertyDescriptors) {
            Method writeMethod = descriptor.getWriteMethod();
            if (writeMethod != null) {
                try {
                    Object value = map.get(descriptor.getName());
                    if (value != null) {
                        writeMethod.invoke(bean, value);
                    }
                } catch (Exception e) {
                    e.printStackTrace();
                }
            }
        }
    }
}

public class StringUtils {
    /** 
     * एक स्ट्रिंग की लंबाई प्राप्त करता है या यदि स्ट्रिंग <code>null</code> है तो <code>0</code> लौटाता है।
     * @param str एक स्ट्रिंग या <code>null</code>
     * @return स्ट्रिंग की लंबाई या यदि स्ट्रिंग <code>null</code> है तो <code>0</code>।
     * @since 2.4
     */
    public static int length(final String str) {
        return str == null ? 0 : str.length();
    }

    public static void main(String[] args) {
        System.out.println(length("Hello")); // Output: 5
        System.out.println(length(null));     // Output: 0
    }
}

public class HexChecker {

    /** 
     * क्या यह एक हेक्स अंक है?
     */
    private static boolean isHex(final char c) {
        return (c >= '0' && c <= '9') || (c >= 'a' && c <= 'f') || (c >= 'A' && c <= 'F');
    }

    public static void main(String[] args) {
        // Test the isHex function
        char testChar1 = 'a';
        char testChar2 = 'G';
        char testChar3 = '5';

        System.out.println(testChar1 + " is hex: " + isHex(testChar1)); // true
        System.out.println(testChar2 + " is hex: " + isHex(testChar2)); // false
        System.out.println(testChar3 + " is hex: " + isHex(testChar3)); // true
    }
}

import java.util.Base64;

public class Base64Decoder {
    /** 
     * एक स्ट्रिंग को Base64 नियम के अनुसार एक स्ट्रिंग में डिकोड करना। 
     */
    public static String base64Decode(final String s) {
        if (s == null || s.isEmpty()) {
            return "";
        }
        byte[] decodedBytes = Base64.getDecoder().decode(s);
        return new String(decodedBytes);
    }

    public static void main(String[] args) {
        String encodedString = "SGVsbG8gV29ybGQ="; // "Hello World" in Base64
        String decodedString = base64Decode(encodedString);
        System.out.println(decodedString); // Output: Hello World
    }
}

public class ArrayLengthChecker {

    /** 
     * <p>जांचता है कि क्या दो ऐरे एक ही लंबाई के हैं, <code>null</code> ऐरे को लंबाई <code>0</code> के रूप में मानते हुए।</p>
     * @param array1 पहला ऐरे, <code>null</code> हो सकता है
     * @param array2 दूसरा ऐरे, <code>null</code> हो सकता है
     * @return <code>true</code> यदि ऐरे की लंबाई मेल खाती है, <code>null</code> को एक खाली ऐरे के रूप में मानते हुए
     */
    public static boolean isSameLength(final double[] array1, final double[] array2) {
        int length1 = (array1 == null) ? 0 : array1.length;
        int length2 = (array2 == null) ? 0 : array2.length;
        return length1 == length2;
    }

    public static void main(String[] args) {
        double[] array1 = {1.0, 2.0, 3.0};
        double[] array2 = {4.0, 5.0, 6.0};
        double[] array3 = null;

        System.out.println(isSameLength(array1, array2)); // true
        System.out.println(isSameLength(array1, array3)); // false
        System.out.println(isSameLength(array3, array3)); // true
    }
}

