import java.io.UnsupportedEncodingException;
import java.net.URLEncoder;

public class TemplateEncoder {
    /** 
     * एक स्ट्रिंग को एन्कोड करता है जिसमें टेम्पलेट पैरामीटर नाम मौजूद होते हैं, विशेष रूप से '{' और '}' अक्षरों को प्रतिशत-कोडित किया जाएगा।
     * @param s वह स्ट्रिंग जिसमें शून्य या अधिक टेम्पलेट पैरामीटर नाम हैं
     * @return एन्कोडेड टेम्पलेट पैरामीटर नामों के साथ स्ट्रिंग।
     */
    public static String encodeTemplateNames(String s) {
        if (s == null) {
            return null;
        }

        StringBuilder encodedString = new StringBuilder();
        for (char c : s.toCharArray()) {
            if (c == '{') {
                encodedString.append(URLEncoder.encode("{", java.nio.charset.StandardCharsets.UTF_8));
            } else if (c == '}') {
                encodedString.append(URLEncoder.encode("}", java.nio.charset.StandardCharsets.UTF_8));
            } else {
                encodedString.append(c);
            }
        }
        return encodedString.toString();
    }

    public static void main(String[] args) {
        String input = "Hello {name}, welcome to {place}!";
        String encoded = encodeTemplateNames(input);
        System.out.println(encoded);
    }
}

import java.awt.geom.Point2D;

public class PointComparison {

    /** 
     * दो बिंदुओं की समानता की तुलना करें, सहिष्णुता 1e-9 का उपयोग करते हुए।
     * @param p1 पहला बिंदु
     * @param p2 दूसरा बिंदु
     * @return क्या दोनों बिंदु समान हैं या नहीं
     */
    public static boolean equals(Point2D p1, Point2D p2) {
        if (p1 == null || p2 == null) {
            return false;
        }
        double tolerance = 1e-9;
        return Math.abs(p1.getX() - p2.getX()) < tolerance && Math.abs(p1.getY() - p2.getY()) < tolerance;
    }

    public static void main(String[] args) {
        Point2D point1 = new Point2D.Double(1.000000001, 2.0);
        Point2D point2 = new Point2D.Double(1.0, 2.0);
        System.out.println(equals(point1, point2)); // Should print true
    }
}

