import java.nio.file.Path;
import java.nio.file.Paths;

public class PathUtil {
    /** 
     * दिए गए पथ पर दिए गए सापेक्ष पथ को लागू करें, मानते हुए कि मानक जावा फ़ोल्डर विभाजन (यानी "/" विभाजक) है।
     * @param path वह पथ जिससे शुरू करना है (आमतौर पर एक पूर्ण फ़ाइल पथ)
     * @param relativePath लागू करने के लिए सापेक्ष पथ (ऊपर दिए गए पूर्ण फ़ाइल पथ के सापेक्ष)
     * @return वह पूर्ण फ़ाइल पथ जो सापेक्ष पथ को लागू करने से प्राप्त होता है
     */
    public static String applyRelativePath(String path, String relativePath) {
        Path basePath = Paths.get(path);
        Path resolvedPath = basePath.resolveSibling(relativePath);
        return resolvedPath.toString();
    }

    public static void main(String[] args) {
        String path = "/home/user/documents";
        String relativePath = "../pictures/image.png";
        String result = applyRelativePath(path, relativePath);
        System.out.println(result); // Output: /home/user/pictures/image.png
    }
}

public class StringSearch {

    /** 
     * एक स्ट्रिंग के भीतर पहला इंडेक्स खोजता है, <code>null</code> को संभालते हुए। यह विधि {@link String#indexOf(String)} का उपयोग करती है। 
     */
    public static int indexOf(String str, String searchStr) {
        if (str == null || searchStr == null) {
            return -1; // यदि कोई भी स्ट्रिंग null है, तो -1 लौटाएं
        }
        return str.indexOf(searchStr); // स्ट्रिंग के भीतर खोजें
    }

    public static void main(String[] args) {
        // परीक्षण के लिए कुछ उदाहरण
        System.out.println(indexOf("Hello, world!", "world")); // 7
        System.out.println(indexOf("Hello, world!", "Java"));  // -1
        System.out.println(indexOf(null, "test"));              // -1
        System.out.println(indexOf("test", null));              // -1
    }
}

import java.util.Arrays;

public class Main {
    /**
     * एक नई स्ट्रिंग्स की ऐरे लौटाता है जिसमें कोई नल तत्व नहीं है। यह आंतरिक विधि एक्सक्लूड सूचियों (ऐरे और संग्रह) को सामान्य बनाने के लिए उपयोग की जाती है। ध्यान दें कि {@link Arrays#sort(Object[])} एक {@link NullPointerException} फेंकेगा यदि ऐरे का कोई तत्व <code>null</code> है।
     * @param array जाँचने के लिए ऐरे
     * @return दिया गया ऐरे या एक नई ऐरे जिसमें नल नहीं है।
     */
    static String[] toNoNullStringArray(Object[] array) {
        if (array == null) {
            return new String[0];
        }
        return Arrays.stream(array)
                     .filter(obj -> obj != null)
                     .map(Object::toString)
                     .toArray(String[]::new);
    }

    public static void main(String[] args) {
        Object[] inputArray = { "Hello", null, "World", null, "!" };
        String[] resultArray = toNoNullStringArray(inputArray);
        System.out.println(Arrays.toString(resultArray)); // Output: [Hello, World, !]
    }
}

public class FileExtensionUtil {

    /**
     * अंतिम एक्सटेंशन सेपरेटर कैरेक्टर का इंडेक्स लौटाता है, जो कि एक डॉट है। <p> यह मेथड यह भी जांचता है कि अंतिम डॉट के बाद कोई डायरेक्टरी सेपरेटर नहीं है। ऐसा करने के लिए यह {@link #indexOfLastSeparator(String)} का उपयोग करता है, जो कि Unix या Windows फॉर्मेट में फाइल को संभालेगा। <p> आउटपुट उस मशीन के अनुसार समान होगा जिस पर कोड चल रहा है।
     * @param filename  वह फाइल का नाम जिसमें अंतिम पथ सेपरेटर को खोजना है, null पर -1 लौटाता है
     * @return अंतिम सेपरेटर कैरेक्टर का इंडेक्स, या -1 यदि ऐसा कोई कैरेक्टर नहीं है
     */
    public static int indexOfExtension(String filename) {
        if (filename == null) {
            return -1;
        }

        int lastDotIndex = filename.lastIndexOf('.');
        int lastSeparatorIndex = indexOfLastSeparator(filename);

        // Check if the last dot is after the last separator
        if (lastDotIndex > lastSeparatorIndex) {
            return lastDotIndex;
        }

        return -1;
    }

    /**
     * अंतिम पथ सेपरेटर का इंडेक्स लौटाता है। यह Unix और Windows दोनों फॉर्मेट के लिए काम करता है।
     * @param filename  वह फाइल का नाम जिसमें अंतिम पथ सेपरेटर को खोजना है
     * @return अंतिम पथ सेपरेटर का इंडेक्स, या -1 यदि ऐसा कोई कैरेक्टर नहीं है
     */
    private static int indexOfLastSeparator(String filename) {
        int lastUnixSeparator = filename.lastIndexOf('/');
        int lastWindowsSeparator = filename.lastIndexOf('\\');
        return Math.max(lastUnixSeparator, lastWindowsSeparator);
    }

    public static void main(String[] args) {
        // Example usage
        String filename = "example/path/to/file.txt";
        int index = indexOfExtension(filename);
        System.out.println("Index of last extension separator: " + index);
    }
}

public class CacheManager {

    /** 
     * @param timestamp        वर्तमान समय का टाइमस्टैम्प
     * @param expiredThreshold पिछले अपडेट समय और कैश से हटाए जाने वाले समय बिंदु के बीच की अवधि को दर्शाता है।
     * @return true का मतलब है कि इस मेट्रिक को कैश से हटाया जाना चाहिए।
     */
    public boolean isExpired(long timestamp, long expiredThreshold) {
        long currentTime = System.currentTimeMillis();
        return (currentTime - timestamp) > expiredThreshold;
    }

    public static void main(String[] args) {
        CacheManager cacheManager = new CacheManager();
        long timestamp = System.currentTimeMillis() - 5000; // 5 seconds ago
        long expiredThreshold = 3000; // 3 seconds

        boolean result = cacheManager.isExpired(timestamp, expiredThreshold);
        System.out.println("Is expired: " + result); // Should print true
    }
}

