    }

    /** 
     * एक फ़ील्ड टैग पढ़ने का प्रयास करें, यदि हम EOF पर पहुँच गए हैं तो शून्य लौटाएँ। प्रोटोकॉल संदेश पार्सर टैग पढ़ने के लिए इसका उपयोग करते हैं, क्योंकि एक प्रोटोकॉल संदेश वैध रूप से किसी भी टैग के स्थान पर समाप्त हो सकता है, और शून्य एक मान्य टैग संख्या नहीं है।
     */
    public int readTag() throws IOException {
        int tag = inputStream.read();
        if (tag == -1) {
            return 0; // EOF reached
        }
        return tag;
    }
}

import java.util.Arrays;

class ByteVector {
    private byte[] data;
    private int size;

    public ByteVector() {
        this.data = new byte[2]; // Initial capacity
        this.size = 0;
    }

    public void put(byte value) {
        if (size == data.length) {
            resize();
        }
        data[size++] = value;
    }

    private void resize() {
        data = Arrays.copyOf(data, data.length * 2);
    }

    public byte[] toArray() {
        return Arrays.copyOf(data, size);
    }
}

public class Main {
    /**
     * इस बाइट वेक्टर में दो बाइट डालता है। यदि आवश्यक हो तो बाइट वेक्टर स्वचालित रूप से बड़ा हो जाता है।
     * @param byteValue1 एक बाइट।
     * @param byteValue2 एक और बाइट।
     * @return यह बाइट वेक्टर।
     */
    final ByteVector put11(final int byteValue1, final int byteValue2) {
        ByteVector byteVector = new ByteVector();
        byteVector.put((byte) byteValue1);
        byteVector.put((byte) byteValue2);
        return byteVector;
    }

    public static void main(String[] args) {
        Main main = new Main();
        ByteVector result = main.put11(10, 20);
        System.out.println(Arrays.toString(result.toArray()));
    }
}

public class ContentRangeBuilder {

    /**
     * 'Content-Range' HTTP हेडर मान बनाएं।
     * @return 'Content-Range' मान
     */
    private String buildContentRange() {
        long start = 0; // प्रारंभिक बाइट
        long end = 499; // अंतिम बाइट
        long total = 1234; // कुल बाइट्स

        return String.format("bytes %d-%d/%d", start, end, total);
    }

    public static void main(String[] args) {
        ContentRangeBuilder builder = new ContentRangeBuilder();
        String contentRange = builder.buildContentRange();
        System.out.println(contentRange);
    }
}

import java.io.BufferedReader;
import java.io.File;
import java.io.FileReader;
import java.io.IOException;
import java.util.ArrayList;
import java.util.List;

class ProfileAnalyzeTimeRange {
    private long startTime;
    private long endTime;

    public ProfileAnalyzeTimeRange(long startTime, long endTime) {
        this.startTime = startTime;
        this.endTime = endTime;
    }

    public long getStartTime() {
        return startTime;
    }

    public long getEndTime() {
        return endTime;
    }
}

class ThreadSnapshot {
    private long timestamp;
    private String threadInfo;

    public ThreadSnapshot(long timestamp, String threadInfo) {
        this.timestamp = timestamp;
        this.threadInfo = threadInfo;
    }

    public long getTimestamp() {
        return timestamp;
    }

    public String getThreadInfo() {
        return threadInfo;
    }
}

public class ThreadSnapshotLoader {

    /** 
     * निर्दिष्ट समय सीमा में थ्रेड स्नैपशॉट लोड करें
     */
    public static List<ThreadSnapshot> parseFromFileWithTimeRange(File file, List<ProfileAnalyzeTimeRange> timeRanges) throws IOException {
        List<ThreadSnapshot> snapshots = new ArrayList<>();

        try (BufferedReader br = new BufferedReader(new FileReader(file))) {
            String line;
            while ((line = br.readLine()) != null) {
                String[] parts = line.split(",");
                long timestamp = Long.parseLong(parts[0]);
                String threadInfo = parts[1];

                for (ProfileAnalyzeTimeRange range : timeRanges) {
                    if (timestamp >= range.getStartTime() && timestamp <= range.getEndTime()) {
                        snapshots.add(new ThreadSnapshot(timestamp, threadInfo));
                        break; // No need to check other ranges if already added
                    }
                }
            }
        }

        return snapshots;
    }
}
